func bothModelKeysPresent() async throws {
    let dir = makeTempDir()
    mockHTTP200(json: """
    {"five_hour":{"utilization":42,"resets_at":"2026-04-17T15:00:00Z"},
     "seven_day":{"utilization":8,"resets_at":"2026-04-23T21:00:00Z"},
